Get-WmiObject Win32_Service | ForEach-Object {
    $svc = $_.Name
    $sd = (sc.exe sdshow $svc 2>$null)
    if ($sd -match 'WD|WO|RC') { Write-Output "$svc : $sd" }
}

Get-WmiObject Win32_Service | Where-Object { $_.StartName -eq 'LocalSystem' } | ForEach-Object {
    $path = ($_.PathName -replace '"','').Split(' ')[0]
    if (Test-Path $path) {
        $acl = Get-Acl $path
        $acl.Access | Where-Object { $_.FileSystemRights -match 'Write|FullControl' -and
            $_.IdentityReference -notmatch 'SYSTEM|Administrators|TrustedInstaller' } |
            ForEach-Object { Write-Output "$path : $($_.IdentityReference) : $($_.FileSystemRights)" }
    }
}

Get-ChildItem 'HKLM:\SYSTEM\CurrentControlSet\Services' | ForEach-Object {
    $fc = (Get-ItemProperty $_.PSPath -Name FailureCommand -ErrorAction SilentlyContinue).FailureCommand
    if ($fc) { Write-Output "$($_.PSChildName): $fc" }
}

Get-Service | ForEach-Object {
    $dep = $_.DependentServices
    if ($dep.Count -gt 0) {
        Write-Output "$($_.Name) is required by: $($dep.Name -join ', ')"
    }
}

Get-WmiObject Win32_Service | Where-Object { $_.PathName -match ' ' -and $_.PathName -notmatch '"' } | ForEach-Object {
    $parts = $_.PathName -split ' '
    $cumulative = ''
    for ($i = 0; $i -lt $parts.Count - 1; $i++) {
        $cumulative += ($i -eq 0 ? $parts[$i] : ' ' + $parts[$i])
        $testPath = $cumulative + '.exe'
        $parentDir = Split-Path $cumulative
        $acl = Get-Acl $parentDir -ErrorAction SilentlyContinue
        $acl.Access | Where-Object {
            $_.FileSystemRights -match 'Write|FullControl' -and
            $_.IdentityReference -notmatch 'SYSTEM|Administrators|TrustedInstaller'
        } | ForEach-Object {
            Write-Output "Writable dir: $parentDir -> Place: $testPath"
        }
    }
}
